+import { pool } from '../config/database';
+import { User, CreateUserInput, UpdateUserInput, UserFilters } from '../models/user';
+import { hash } from 'bcrypt';
+import { randomUUID } from 'crypto';
+
+const SALT_ROUNDS = 12;
+
+export class UserRepository {
+  async create(input: CreateUserInput): Promise<User> {
+    const id = randomUUID();
+    const passwordHash = await hash(input.password, SALT_ROUNDS);
+    const now = new Date();
+    await pool.query(
+      'INSERT INTO users (id, email, first_name, last_name, password_hash, role, status, created_at, updated_at) VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)',
+      [id, input.email, input.firstName, input.lastName, passwordHash, input.role ?? 'viewer', 'active', now, now]
+    );
+    return { id, email: input.email, firstName: input.firstName, lastName: input.lastName, role: input.role ?? 'viewer', status: 'active', createdAt: now, updatedAt: now };
+  }
+
+  async findById(id: string): Promise<User | null> {
+    const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [id]);
+    return rows[0] ?? null;
+  }
+
+  async findByEmail(email: string): Promise<User | null> {
+    const { rows } = await pool.query('SELECT * FROM users WHERE email = $1', [email]);
+    return rows[0] ?? null;
+  }
+
+  async findAll(filters?: UserFilters): Promise<User[]> {
+    let sql = 'SELECT * FROM users WHERE 1=1';
+    const params: unknown[] = [];
+    let idx = 1;
+    if (filters?.role) { sql += ` AND role = $${idx++}`; params.push(filters.role); }
+    if (filters?.status) { sql += ` AND status = $${idx++}`; params.push(filters.status); }
+    if (filters?.search) { sql += ` AND (first_name ILIKE $${idx} OR last_name ILIKE $${idx} OR email ILIKE $${idx})`; params.push(`%${filters.search}%`); idx++; }
+    sql += ' ORDER BY created_at DESC';
+    if (filters?.limit) { sql += ` LIMIT $${idx++}`; params.push(filters.limit); }
+    if (filters?.offset) { sql += ` OFFSET $${idx++}`; params.push(filters.offset); }
+    const { rows } = await pool.query(sql, params);
+    return rows;
+  }
+
+  async update(id: string, input: UpdateUserInput): Promise<void> {
+    const sets: string[] = [];
+    const params: unknown[] = [];
+    let idx = 1;
+    if (input.firstName) { sets.push(`first_name = $${idx++}`); params.push(input.firstName); }
+    if (input.lastName) { sets.push(`last_name = $${idx++}`); params.push(input.lastName); }
+    if (input.role) { sets.push(`role = $${idx++}`); params.push(input.role); }
+    if (input.status) { sets.push(`status = $${idx++}`); params.push(input.status); }
+    sets.push(`updated_at = $${idx++}`); params.push(new Date());
+    params.push(id);
+    await pool.query(`UPDATE users SET ${sets.join(', ')} WHERE id = $${idx}`, params);
+  }
+
+  async delete(id: string): Promise<void> {
+    await pool.query('DELETE FROM users WHERE id = $1', [id]);
+  }
+}
