+import { pool } from '../config/database';
+import { Session, SessionInput, TokenPair } from '../models/session';
+import { randomUUID } from 'crypto';
+import { sign } from 'jsonwebtoken';
+
+const JWT_SECRET = process.env.JWT_SECRET ?? 'dev-secret';
+const DEFAULT_TTL = 86400;
+
+export class SessionRepository {
+  async create(input: SessionInput): Promise<TokenPair> {
+    const id = randomUUID();
+    const ttl = input.ttlSeconds ?? DEFAULT_TTL;
+    const accessToken = sign({ sub: input.userId, sid: id }, JWT_SECRET, { expiresIn: ttl });
+    const refreshToken = randomUUID();
+    const expiresAt = new Date(Date.now() + ttl * 1000);
+    await pool.query(
+      'INSERT INTO sessions (id, user_id, token, refresh_token, expires_at) VALUES ($1,$2,$3,$4,$5)',
+      [id, input.userId, accessToken, refreshToken, expiresAt]
+    );
+    return { accessToken, refreshToken, expiresIn: ttl };
+  }
+
+  async findByToken(token: string): Promise<Session | null> {
+    const { rows } = await pool.query('SELECT * FROM sessions WHERE token = $1 AND expires_at > NOW()', [token]);
+    return rows[0] ?? null;
+  }
+
+  async findByRefreshToken(refreshToken: string): Promise<Session | null> {
+    const { rows } = await pool.query('SELECT * FROM sessions WHERE refresh_token = $1', [refreshToken]);
+    return rows[0] ?? null;
+  }
+
+  async deleteByUserId(userId: string): Promise<void> {
+    await pool.query('DELETE FROM sessions WHERE user_id = $1', [userId]);
+  }
+}
