+import { pool } from '../config/database';
+import { Notification, NotificationInput, NotificationFilters, NotificationStats } from '../models/notification';
+import { randomUUID } from 'crypto';
+
+export class NotificationRepository {
+  async create(input: NotificationInput): Promise<Notification> {
+    const id = randomUUID();
+    const now = new Date();
+    await pool.query(
+      'INSERT INTO notifications (id, user_id, type, title, body, read, created_at) VALUES ($1,$2,$3,$4,$5,$6,$7)',
+      [id, input.userId, input.type, input.title, input.body, false, now]
+    );
+    return { id, userId: input.userId, type: input.type, title: input.title, body: input.body, read: false, createdAt: now };
+  }
+
+  async findAll(filters: NotificationFilters): Promise<Notification[]> {
+    let sql = 'SELECT * FROM notifications WHERE user_id = $1';
+    const params: unknown[] = [filters.userId];
+    let idx = 2;
+    if (filters.read !== undefined) { sql += ` AND read = $${idx++}`; params.push(filters.read); }
+    if (filters.type) { sql += ` AND type = $${idx++}`; params.push(filters.type); }
+    sql += ' ORDER BY created_at DESC';
+    if (filters.limit) { sql += ` LIMIT $${idx++}`; params.push(filters.limit); }
+    const { rows } = await pool.query(sql, params);
+    return rows;
+  }
+
+  async markAsRead(id: string): Promise<void> {
+    await pool.query('UPDATE notifications SET read = true WHERE id = $1', [id]);
+  }
+
+  async markAllAsRead(userId: string): Promise<void> {
+    await pool.query('UPDATE notifications SET read = true WHERE user_id = $1 AND read = false', [userId]);
+  }
+
+  async getStats(userId: string): Promise<NotificationStats> {
+    const { rows } = await pool.query(
+      'SELECT type, COUNT(*) as count, COUNT(*) FILTER (WHERE read = false) as unread FROM notifications WHERE user_id = $1 GROUP BY type',
+      [userId]
+    );
+    const total = rows.reduce((sum: number, r: { count: number }) => sum + Number(r.count), 0);
+    const unread = rows.reduce((sum: number, r: { unread: number }) => sum + Number(r.unread), 0);
+    const byType = {} as Record<string, number>;
+    for (const row of rows) {
+      byType[row.type as string] = Number(row.count);
+    }
+    return { total, unread, byType } as NotificationStats;
+  }
+}
