+import { pool } from '../config/database';
+import { AuditEntry, AuditInput, AuditQuery } from '../models/audit';
+import { randomUUID } from 'crypto';
+
+export class AuditRepository {
+  async log(input: AuditInput): Promise<void> {
+    const id = randomUUID();
+    await pool.query(
+      'INSERT INTO audit_logs (id, user_id, action, resource, resource_id, details, timestamp) VALUES ($1,$2,$3,$4,$5,$6,$7)',
+      [id, input.userId, input.action, input.resource, input.resourceId, JSON.stringify(input.details ?? {}), new Date()]
+    );
+  }
+
+  async query(params: AuditQuery): Promise<AuditEntry[]> {
+    let sql = 'SELECT * FROM audit_logs WHERE 1=1';
+    const values: unknown[] = [];
+    let idx = 1;
+    if (params.userId) { sql += ` AND user_id = $${idx++}`; values.push(params.userId); }
+    if (params.action) { sql += ` AND action = $${idx++}`; values.push(params.action); }
+    if (params.resource) { sql += ` AND resource = $${idx++}`; values.push(params.resource); }
+    if (params.from) { sql += ` AND timestamp >= $${idx++}`; values.push(params.from); }
+    if (params.to) { sql += ` AND timestamp <= $${idx++}`; values.push(params.to); }
+    sql += ' ORDER BY timestamp DESC';
+    if (params.limit) { sql += ` LIMIT $${idx++}`; values.push(params.limit); }
+    const { rows } = await pool.query(sql, values);
+    return rows;
+  }
+}
