+import { NotificationRepository } from '../repositories/notification-repo';
+import { Notification, NotificationInput, NotificationFilters } from '../models/notification';
+
+export class NotificationService {
+  private repo: NotificationRepository;
+
+  constructor(repo?: NotificationRepository) {
+    this.repo = repo ?? new NotificationRepository();
+  }
+
+  async send(input: NotificationInput): Promise<Notification> {
+    return this.repo.create(input);
+  }
+
+  async getForUser(userId: string, unreadOnly = false): Promise<Notification[]> {
+    return this.repo.findAll({ userId, read: unreadOnly ? false : undefined });
+  }
+
+  async markRead(notificationId: string): Promise<void> {
+    await this.repo.markAsRead(notificationId);
+  }
+
+  async markAllRead(userId: string): Promise<void> {
+    await this.repo.markAllAsRead(userId);
+  }
+
+  async getUnreadCount(userId: string): Promise<number> {
+    const stats = await this.repo.getStats(userId);
+    return stats.unread;
+  }
+}
