+import { compare } from 'bcrypt';
+import { UserRepository } from '../repositories/user-repo';
+import { SessionRepository } from '../repositories/session-repo';
+import { AuditRepository } from '../repositories/audit-repo';
+import { TokenPair } from '../models/session';
+
+export class AuthService {
+  private userRepo: UserRepository;
+  private sessionRepo: SessionRepository;
+  private auditRepo: AuditRepository;
+
+  constructor() {
+    this.userRepo = new UserRepository();
+    this.sessionRepo = new SessionRepository();
+    this.auditRepo = new AuditRepository();
+  }
+
+  async login(email: string, password: string): Promise<TokenPair | null> {
+    const user = await this.userRepo.findByEmail(email);
+    if (!user) return null;
+    const userWithPw = user as unknown as { passwordHash: string; id: string };
+    const valid = await compare(password, userWithPw.passwordHash);
+    if (!valid) {
+      await this.auditRepo.log({ userId: userWithPw.id, action: 'login_failed', resource: 'auth', resourceId: userWithPw.id });
+      return null;
+    }
+    const tokens = await this.sessionRepo.create({ userId: userWithPw.id });
+    await this.auditRepo.log({ userId: userWithPw.id, action: 'login', resource: 'auth', resourceId: userWithPw.id });
+    return tokens;
+  }
+
+  async logout(userId: string): Promise<void> {
+    await this.sessionRepo.deleteByUserId(userId);
+    await this.auditRepo.log({ userId, action: 'logout', resource: 'auth', resourceId: userId });
+  }
+
+  async refresh(refreshToken: string): Promise<TokenPair | null> {
+    const session = await this.sessionRepo.findByRefreshToken(refreshToken);
+    if (!session) return null;
+    await this.sessionRepo.deleteByUserId(session.userId);
+    return this.sessionRepo.create({ userId: session.userId });
+  }
+}
